/**
 * @file hms-media-provider.ts
 * @description HMS (100ms.live) implementation of IMediaProvider.
 * @layer Services
 *
 * Uses @100mslive/hms-video-store (vanilla JS, NOT the React SDK) to implement
 * the IMediaProvider interface. This keeps the provider framework-agnostic.
 *
 * The React SDK (@100mslive/react-sdk) should only be used in the React hooks
 * layer or directly by consumers building React apps.
 *
 * NOTE: This is for multi-party conference rooms only. 1:1 P2P calls use
 * PeerJS via CallsService -- a completely separate system.
 */

import {
  HMSReactiveStore,
  selectPeers,
  selectLocalPeer,
  selectRoomState,
  HMSRoomState,
} from '@100mslive/hms-video-store';

import type { HMSPeer } from '@100mslive/hms-video-store';

import type {
  IMediaProvider,
  DialMediaDeviceInfo,
  MediaConnectionState,
  MediaPeer,
  MediaTrack,
  MediaSessionCredentials,
  MediaProviderConfig,
  MediaProviderEvents,
} from '@dial-wtf/core';

type EventCallback<K extends keyof MediaProviderEvents> = (
  payload: MediaProviderEvents[K],
) => void;

/**
 * HMS implementation of the IMediaProvider interface.
 *
 * Uses the vanilla @100mslive/hms-video-store SDK under the hood.
 * Subscribe to events via on()/off() for reactive updates.
 */
export class HMSMediaProvider implements IMediaProvider {
  private hmsStore: ReturnType<HMSReactiveStore['getStore']>;
  private hmsActions: ReturnType<HMSReactiveStore['getActions']>;
  private listeners: Map<string, Set<EventCallback<any>>> = new Map();
  private unsubscribers: Array<() => void> = [];
  private connectionState: MediaConnectionState = 'disconnected';

  constructor() {
    const hms = new HMSReactiveStore();
    this.hmsStore = hms.getStore();
    this.hmsActions = hms.getActions();
  }

  // -- Connection lifecycle ---------------------------------------------------

  async connect(
    credentials: MediaSessionCredentials,
    config?: MediaProviderConfig,
  ): Promise<void> {
    this.connectionState = 'connecting';
    this.emit('connection-state-changed', { state: 'connecting' });

    try {
      await this.hmsActions.join({
        authToken: credentials.authToken,
        userName: credentials.userName,
        settings: {
          isAudioMuted: config?.initialAudio === false,
          isVideoMuted: config?.initialVideo !== true,
        },
      });

      this.connectionState = 'connected';
      this.emit('connection-state-changed', { state: 'connected' });
      this.subscribeToStoreUpdates();
    } catch (err) {
      this.connectionState = 'failed';
      this.emit('connection-state-changed', { state: 'failed' });
      this.emit('error', {
        code: 'HMS_JOIN_FAILED',
        message: err instanceof Error ? err.message : String(err),
      });
      throw err;
    }
  }

  async disconnect(): Promise<void> {
    this.cleanupSubscriptions();
    try {
      await this.hmsActions.leave();
    } finally {
      this.connectionState = 'disconnected';
      this.emit('connection-state-changed', { state: 'disconnected' });
    }
  }

  getConnectionState(): MediaConnectionState {
    return this.connectionState;
  }

  // -- Local track controls ---------------------------------------------------

  async setLocalAudioEnabled(enabled: boolean): Promise<void> {
    await this.hmsActions.setLocalAudioEnabled(enabled);
  }

  async setLocalVideoEnabled(enabled: boolean): Promise<void> {
    await this.hmsActions.setLocalVideoEnabled(enabled);
  }

  async startScreenShare(): Promise<void> {
    await this.hmsActions.setScreenShareEnabled(true);
  }

  async stopScreenShare(): Promise<void> {
    await this.hmsActions.setScreenShareEnabled(false);
  }

  // -- Peers & tracks ---------------------------------------------------------

  getPeers(): MediaPeer[] {
    const hmsPeers = this.hmsStore.getState(selectPeers);
    return hmsPeers.map((p: HMSPeer) => this.mapPeer(p));
  }

  getLocalPeer(): MediaPeer | null {
    const localPeer = this.hmsStore.getState(selectLocalPeer);
    return localPeer ? this.mapPeer(localPeer) : null;
  }

  // -- Device management ------------------------------------------------------

  async getAudioDevices(): Promise<DialMediaDeviceInfo[]> {
    const devices = await navigator.mediaDevices.enumerateDevices();
    return devices.filter((d) => d.kind === 'audioinput');
  }

  async getVideoDevices(): Promise<DialMediaDeviceInfo[]> {
    const devices = await navigator.mediaDevices.enumerateDevices();
    return devices.filter((d) => d.kind === 'videoinput');
  }

  async setAudioDevice(deviceId: string): Promise<void> {
    await this.hmsActions.setAudioSettings({ deviceId });
  }

  async setVideoDevice(deviceId: string): Promise<void> {
    await this.hmsActions.setVideoSettings({ deviceId });
  }

  // -- Events -----------------------------------------------------------------

  on<K extends keyof MediaProviderEvents>(
    event: K,
    callback: EventCallback<K>,
  ): void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(callback);
  }

  off<K extends keyof MediaProviderEvents>(
    event: K,
    callback: EventCallback<K>,
  ): void {
    this.listeners.get(event)?.delete(callback);
  }

  // -- Private helpers --------------------------------------------------------

  private emit<K extends keyof MediaProviderEvents>(
    event: K,
    payload: MediaProviderEvents[K],
  ): void {
    const callbacks = this.listeners.get(event);
    if (!callbacks) return;
    for (const cb of callbacks) {
      try {
        cb(payload);
      } catch (err) {
        console.warn(`[HMSMediaProvider] Error in ${event} listener:`, err);
      }
    }
  }

  private subscribeToStoreUpdates(): void {
    // Track peer list changes
    let previousPeerIds = new Set<string>();

    const unsubPeers = this.hmsStore.subscribe((peers: HMSPeer[]) => {
      const currentPeerIds = new Set(peers.map((p: HMSPeer) => p.id));

      // Detect joins
      for (const peer of peers) {
        if (!previousPeerIds.has(peer.id)) {
          this.emit('peer-joined', { peer: this.mapPeer(peer) });
        }
      }

      // Detect leaves
      for (const prevId of previousPeerIds) {
        if (!currentPeerIds.has(prevId)) {
          this.emit('peer-left', {
            peer: { id: prevId, name: '', role: '', isLocal: false },
          });
        }
      }

      previousPeerIds = currentPeerIds;
    }, selectPeers);

    this.unsubscribers.push(unsubPeers);

    // Track room state for reconnection detection
    const unsubRoom = this.hmsStore.subscribe((roomState: HMSRoomState) => {
      if (roomState === HMSRoomState.Reconnecting) {
        this.connectionState = 'reconnecting';
        this.emit('connection-state-changed', { state: 'reconnecting' });
      } else if (
        roomState === HMSRoomState.Connected &&
        this.connectionState === 'reconnecting'
      ) {
        this.connectionState = 'connected';
        this.emit('connection-state-changed', { state: 'connected' });
      } else if (
        roomState === HMSRoomState.Disconnected ||
        roomState === HMSRoomState.Failed
      ) {
        const state: MediaConnectionState =
          roomState === HMSRoomState.Failed ? 'failed' : 'disconnected';
        this.connectionState = state;
        this.emit('connection-state-changed', { state });
      }
    }, selectRoomState);

    this.unsubscribers.push(unsubRoom);
  }

  private cleanupSubscriptions(): void {
    for (const unsub of this.unsubscribers) {
      unsub();
    }
    this.unsubscribers = [];
  }

  private mapPeer(hmsPeer: HMSPeer): MediaPeer {
    return {
      id: hmsPeer.id,
      name: hmsPeer.name,
      role: hmsPeer.roleName ?? '',
      isLocal: hmsPeer.isLocal,
      audioTrack: hmsPeer.audioTrack
        ? this.mapTrack(hmsPeer.audioTrack, hmsPeer.id, 'audio')
        : undefined,
      videoTrack: hmsPeer.videoTrack
        ? this.mapTrack(hmsPeer.videoTrack, hmsPeer.id, 'video')
        : undefined,
      screenTrack: undefined,
    };
  }

  private mapTrack(
    trackId: string,
    peerId: string,
    kind: 'audio' | 'video',
  ): MediaTrack {
    return {
      id: trackId,
      peerId,
      kind,
      source: 'regular',
      enabled: true,
    };
  }
}
